	LL_USART_EnableIT_RXNE(USART2);			//Generowanie przerwania gdy odbierze dane

	//ADC
	LL_APB2_GRP1_EnableClock(LL_APB2_GRP1_PERIPH_ADC1);					//Uruchomienie APB2 dla ADC1
	LL_GPIO_SetPinMode(GPIOA, LL_GPIO_PIN_0, LL_GPIO_MODE_ANALOG);		//Ustawienie pinu na Analog
	LL_GPIO_SetPinPull(GPIOA, LL_GPIO_PIN_0, LL_GPIO_PULL_NO);   		 // Wyłącza rezystory podciągające
	LL_ADC_SetCommonClock(__LL_ADC_COMMON_INSTANCE(ADC1), LL_ADC_PATH_INTERNAL_NONE);
	LL_ADC_SetResolution(ADC1, LL_ADC_RESOLUTION_12B);					//Rozdzielczosc 12-Bitow(wynik 0-4095)
