	LL_ADC_SetSequencersScanMode(ADC1, LL_ADC_SEQ_SCAN_DISABLE);		// Nie skanuj wielu kanałów naraz
	LL_ADC_REG_SetSequencerRanks(ADC1, LL_ADC_REG_RANK_1, LL_ADC_CHANNEL_0);	// PA0 to Kanał 0
	LL_ADC_SetChannelSamplingTime(ADC1, LL_ADC_CHANNEL_0, LL_ADC_SAMPLINGTIME_480CYCLES);
	LL_ADC_Enable(ADC1);
	LL_ADC_REG_SetDMATransfer(ADC1, LL_ADC_REG_DMA_TRANSFER_UNLIMITED);


	//WatchDogs IWDG
	LL_IWDG_Enable(IWDG);									// Uruchomienie IWDG (to automatycznie włącza też zegar LSI)
	LL_IWDG_EnableWriteAccess(IWDG);						// Odblokowanie dostępu do rejestrów (IWDG jest domyślnie chroniony przed zapisem)
	LL_IWDG_SetPrescaler(IWDG, LL_IWDG_PRESCALER_32);		//  Ustawienie dzielnika (Prescaler)
